import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.DtEl18Xn.js";const r="/getbiji-docs-v3/images/XWU6b3QwmoKj2vxi8TscXsTanHf.png",l="/getbiji-docs-v3/images/QJaKbGqmnobTAFx50nqct1vonNP.png",s="/getbiji-docs-v3/images/GTGlbqxmioajWVxpAWocT2iZnjb.png",n="/getbiji-docs-v3/images/DQQWbjSoVo9W3TxlDwCcjqdenDg.png",p="/getbiji-docs-v3/images/SINsbmmm0onF9YxZ5xAcq4Q9nHP.png",h="/getbiji-docs-v3/images/TSlobAA9Eo8EkLx7lF9cQ5lInic.png",d="/getbiji-docs-v3/images/OTanbYUf0or7bhxujoKcF7HBnHb.png",c="/getbiji-docs-v3/images/O1Z7byfrNohminxX7l6chcV4nNa.png",g="/getbiji-docs-v3/images/QXMTbdmpJoSjzfxUs0Tc2c1Cnrb.png",b="/getbiji-docs-v3/images/RHDsb1JYpoMX2pxHjeIc81kunSc.png",m="/getbiji-docs-v3/images/VBUcbq6pqoEbDNxbDIDccs5MnTe.png",u="/getbiji-docs-v3/images/UerQbQQ2voFfpBxQ1mecliFGnue.png",q="/getbiji-docs-v3/images/O5aIbtL7to1s58xjX93cxjxunNd.png",x="/getbiji-docs-v3/images/JMuAbBa5ioUaQfxaVE9cbrKknif.png",P="/getbiji-docs-v3/images/WtwtbUa3LoMbcmxjdnIcqNrJnLc.png",T=JSON.parse('{"title":"常见问题","description":"","frontmatter":{"title":"常见问题","category":"GetSeed AI录音卡","lastUpdated":"2026-03-14T15:00:36.974Z"},"headers":[],"relativePath":"getseed-ai录音卡/常见问题.md","filePath":"getseed-ai录音卡/常见问题.md"}'),G={name:"getseed-ai录音卡/常见问题.md"};function A(f,e,_,k,S,j){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="如何添加设备" tabindex="-1"><strong>如何添加设备？</strong> <a class="header-anchor" href="#如何添加设备" aria-label="Permalink to &quot;**如何添加设备？**&quot;">​</a></h1><ol><li><p>下载Get笔记APP</p></li><li><p>应用商店搜索「Get笔记」，安装并登录</p></li><li><p>长按 MARK 键 1 秒，开启设备（设备不在充电状态）</p></li><li><p>指示灯亮白灯闪烁，代表你的录音卡片已准备好与你的Get笔记APP连接绑定 <img src="'+r+'" alt=""></p></li><li><p>打开Get笔记APP，连接激活</p></li><li><p>打开Get笔记APP，点击首页左上角打开侧边栏菜单，点击“录音卡”，按连接指引操作连接。连接完成后，指示灯将亮白灯常亮。 <img src="'+l+'" alt=""></p></li><li><p>设备连接过程</p></li><li><p>添加设备→连接→连接成功→权益自动下发 <img src="'+s+'" alt=""></p></li></ol><p><img src="'+n+'" alt=""></p><p><img src="'+p+'" alt=""></p><p><img src="'+h+'" alt=""></p><p><img src="'+d+'" alt=""></p><h1 id="为什么搜索不到设备" tabindex="-1">为什么搜索不到设备？ <a class="header-anchor" href="#为什么搜索不到设备" aria-label="Permalink to &quot;为什么搜索不到设备？&quot;">​</a></h1><ol><li>确认蓝牙是否开启，蓝牙开启后再连接设备</li><li>iOS：前往 iPhone 的&quot;设置&quot;，找到 Get笔记APP，确保已启用蓝牙权限</li><li>Android：打开手机设置，启用 Get笔记APP的蓝牙和位置权限（Android 12 之前需选择“始终允许”）</li><li>短按 MARK 键 1 秒，<strong>白灯亮起</strong>，说明设备已开启</li><li>如果设备没有亮起白灯，请使用提供的充电线给你的GetSeed 充电</li><li>充电时紫色指示灯会长亮，充电至少10分钟再尝试连接</li><li>将 GetSeed 设备靠近手机，如果仍未找到设备，可以添加下面的二维码联系我们 <img src="'+c+'" alt=""></li></ol><h1 id="设备连接不上-怎么办" tabindex="-1">设备连接不上，怎么办？ <a class="header-anchor" href="#设备连接不上-怎么办" aria-label="Permalink to &quot;设备连接不上，怎么办？&quot;">​</a></h1><ul><li>A0：确保卡片是有电状态。并将Get笔记APP升级到最新 2.4.3 及以上版本。</li><li>A1： 卡片默认会有3小时休眠，如果您之前连接过，您长按GetSeed录音卡的Mark键1秒，看下能否正常连接，连接成功后可以在Get笔记App里面找到卡片的信息页，对休眠时间进行设置。</li><li>A2：鸿蒙部分机型，需要先在<strong>系统设置-蓝牙-Get-xxxx</strong>进行配对，再去app内进行录音卡连接（如果蓝牙设置里搜不到Get-xxx设备，可以关闭蓝牙开关再打开）</li><li>A3：如果是iOS/华为手机，您之前未从Get笔记App内连接过卡片，而是从手机设置的蓝牙连接的卡片。您需要从手机系统设置-蓝牙-忽略Get-xxxx的设备（或者取消配对），然后从Get笔记App内的侧边栏-&gt;录音卡片进行连接</li><li>A4：如果录音卡固件升级到 ***0.1.5 版本 ***后，无法连接上Get笔记App，可以从手机系统设置-蓝牙-忽略Get-xxxx的设备（或者取消配对），然后从Get笔记App内的侧边栏-&gt;录音卡片进行连接</li><li>A5：如果蓝牙中找不到Get-xxx的录音卡设备（录音卡一直在白灯闪烁），可以在录音卡上，尝试快速先短按MARK键7下（关机，红灯亮一下），再长按MARK键1秒，然后关掉手机蓝牙开关，再打开，再去Get笔记APP里连接录音卡</li><li>A6： 如果您有多台手机，或多台移动设备，请先将之前连接过GetSeed卡片的手机的蓝牙关闭或忽略Get-xxxxx卡片，再使用新的手机设备，在Get笔记App内完成蓝牙的连接。</li><li>A7：固件升级成功后，卡片需要3~5分钟的更新时间，等待完成后即可连接。</li></ul><h1 id="为什么显示的不是录音卡的名称" tabindex="-1">为什么显示的不是录音卡的名称？ <a class="header-anchor" href="#为什么显示的不是录音卡的名称" aria-label="Permalink to &quot;为什么显示的不是录音卡的名称？&quot;">​</a></h1><p>卡片连接弹窗可以左右滑动，找到GetSeed卡片进行设备的链接。</p><h1 id="卡片ota升级后无响应" tabindex="-1">卡片OTA升级后无响应？ <a class="header-anchor" href="#卡片ota升级后无响应" aria-label="Permalink to &quot;卡片OTA升级后无响应？&quot;">​</a></h1><p>固件升级成功后，卡片自己需要3~5分钟的更新时间。在这个过程里，暂时还不能通过APP查看进度，稍等一会即可。</p><h1 id="get笔记侧边栏无法找到-录音卡-选项" tabindex="-1">Get笔记侧边栏无法找到“录音卡”选项？ <a class="header-anchor" href="#get笔记侧边栏无法找到-录音卡-选项" aria-label="Permalink to &quot;Get笔记侧边栏无法找到“录音卡”选项？&quot;">​</a></h1><p>需要将Get笔记App升级到2.4.2及以上版本。</p><h1 id="getseed-可以录手机通话吗" tabindex="-1">GetSeed 可以录手机通话吗？ <a class="header-anchor" href="#getseed-可以录手机通话吗" aria-label="Permalink to &quot;GetSeed 可以录手机通话吗？&quot;">​</a></h1><p><strong>支持</strong>，电话、微信视频、腾讯、钉钉、飞书等线上会议，全都能录。</p><p>现场录音 ↔ 通话录音，可智能识别，自动切换，无需手动操作。</p><ul><li>现场录音场景，会议记录、课堂讲座、采访录音、培训演讲、研讨会等开放环境。</li><li>通话录音，电话采访、微信视频通话、线上会议、电话咨询等通话场景。</li></ul><h1 id="如何使用磁吸卡套" tabindex="-1">如何使用磁吸卡套？ <a class="header-anchor" href="#如何使用磁吸卡套" aria-label="Permalink to &quot;如何使用磁吸卡套？&quot;">​</a></h1><p><strong>苹果手机（iPhone12 及以上）</strong></p><p>**直接吸附：**手机背面自带磁吸功能，将卡套对准吸附即可使用</p><p><img src="'+g+'" alt=""></p><p><strong>安卓/鸿蒙手机</strong></p><p>**贴圈后吸附：**撕下磁吸圈背胶保护膜，将磁吸圈贴于手机背部合适位置，再吸附卡套。</p><p><img src="'+b+'" alt=""></p><h1 id="戴蓝牙耳机的情况-可以录音吗" tabindex="-1">戴蓝牙耳机的情况，可以录音吗？ <a class="header-anchor" href="#戴蓝牙耳机的情况-可以录音吗" aria-label="Permalink to &quot;戴蓝牙耳机的情况，可以录音吗？&quot;">​</a></h1><p><strong>不支持</strong>，录音卡收集的外部环境声音，或手机听筒（骨传导方式收音），无法直接获取蓝牙耳机中播放的声音。</p><h1 id="可以脱离手机单独使用吗" tabindex="-1">可以脱离手机单独使用吗？ <a class="header-anchor" href="#可以脱离手机单独使用吗" aria-label="Permalink to &quot;可以脱离手机单独使用吗？&quot;">​</a></h1><p><strong>可以</strong>，脱离手机依然可以独立录音。</p><p>离线录音时设备可独立工作，录音文件会在 APP 重新连接设备后，自动同步到 APP。</p><h1 id="getseed-录音卡防水吗" tabindex="-1">GetSeed 录音卡防水吗？ <a class="header-anchor" href="#getseed-录音卡防水吗" aria-label="Permalink to &quot;GetSeed 录音卡防水吗？&quot;">​</a></h1><p>不防水，<strong>请避免让设备接触任何液体，以防损坏。</strong></p><h1 id="一般充电多久设备会充满" tabindex="-1">一般充电多久设备会充满？ <a class="header-anchor" href="#一般充电多久设备会充满" aria-label="Permalink to &quot;一般充电多久设备会充满？&quot;">​</a></h1><p>从 0 到 100% 需要约 1.5 小时即可充满电池。</p><h1 id="为什么充电中-开启录音没反应呢" tabindex="-1">为什么充电中，开启录音没反应呢？ <a class="header-anchor" href="#为什么充电中-开启录音没反应呢" aria-label="Permalink to &quot;为什么充电中，开启录音没反应呢？&quot;">​</a></h1><ul><li>充电过程中，无法开启录音；</li><li>录音中，去充电不影响录音，但无法正常充电。</li></ul><h1 id="设备能录多久" tabindex="-1">设备能录多久？ <a class="header-anchor" href="#设备能录多久" aria-label="Permalink to &quot;设备能录多久？&quot;">​</a></h1><p>续航能力强劲，最长连续录音可达 35 小时，待机最长 60 天。</p><h1 id="可以将录音文件传到电脑上吗" tabindex="-1">可以将录音文件传到电脑上吗？ <a class="header-anchor" href="#可以将录音文件传到电脑上吗" aria-label="Permalink to &quot;可以将录音文件传到电脑上吗？&quot;">​</a></h1><p>无法直接传到电脑，设备中录音文件会在连接 Get笔记 APP 后自动同步上传到云端，并进行AI转写和总结，最终生成录音笔记。</p><p>录音笔记本身可以支持音频文件的导出功能。</p><h1 id="如果两部手机经常换着使用-录音卡只能连接一个手机吗-我试了一个手机断开链接-另外一部手机也还是连不上录音卡" tabindex="-1">如果两部手机经常换着使用，录音卡只能连接一个手机吗，我试了一个手机断开链接，另外一部手机也还是连不上录音卡？ <a class="header-anchor" href="#如果两部手机经常换着使用-录音卡只能连接一个手机吗-我试了一个手机断开链接-另外一部手机也还是连不上录音卡" aria-label="Permalink to &quot;如果两部手机经常换着使用，录音卡只能连接一个手机吗，我试了一个手机断开链接，另外一部手机也还是连不上录音卡？&quot;">​</a></h1><p>多部手机使用录音卡，当B手机要连接GetSeed录音卡时，需要将A手机的蓝牙关闭，或者在A手机的系统设置中找到蓝牙选项，把GetSeed录音卡取消配对或忽略此设备。</p><p>这样B手机就可以正常与GetSeed录音卡配对使用了。</p><h1 id="多蓝牙设备引起的卡片连接找不到" tabindex="-1">多蓝牙设备引起的卡片连接找不到 <a class="header-anchor" href="#多蓝牙设备引起的卡片连接找不到" aria-label="Permalink to &quot;多蓝牙设备引起的卡片连接找不到&quot;">​</a></h1><p>卡片连接弹窗可以左右滑动，找到GetSeed卡片进行设备的链接。</p><h1 id="app里一直显示-未找到设备-重试也不成功" tabindex="-1">App里一直显示“未找到设备”，重试也不成功 <a class="header-anchor" href="#app里一直显示-未找到设备-重试也不成功" aria-label="Permalink to &quot;App里一直显示“未找到设备”，重试也不成功&quot;">​</a></h1><p>尝试在手机系统的蓝牙设置里，找到“Get”开头的设备，然后点击“忽略此设备”，再重新尝试几次。</p><h1 id="磁吸导致的手机熄屏-黑屏问题" tabindex="-1">磁吸导致的手机熄屏/黑屏问题 <a class="header-anchor" href="#磁吸导致的手机熄屏-黑屏问题" aria-label="Permalink to &quot;磁吸导致的手机熄屏/黑屏问题&quot;">​</a></h1><p><img src="'+m+'" alt=""></p><h1 id="发芽是什么-发芽怎么用" tabindex="-1">发芽是什么，发芽怎么用？ <a class="header-anchor" href="#发芽是什么-发芽怎么用" aria-label="Permalink to &quot;发芽是什么，发芽怎么用？&quot;">​</a></h1><p><strong>简单来说，就是 AI 帮你把刚才的录音笔记进行“扩展”和“联想”。</strong> 当你录完一条笔记，“发芽”功能会基于你的内容向外探索，结合得到平台优质内容、自己的笔记等内容，自动找出相关的名言、类似的观点或补充背景，帮你把一句话变成一套更有深度的知识。</p><p><strong>举个例子：</strong> 如果你录了一句曾国藩的“既往不恋，当下不杂”，AI 分析后会告诉你：</p><ul><li>爱因斯坦也说过类似的：“我从不去想未来，因为它来得已经够快了”；</li><li>甚至《功夫熊猫》里也有同款金句：“昨天是历史，明天是谜题，今天是礼物。” 它可以帮你发现这些跨越时空的思想共鸣。 <strong>使用规则（3点必读）：</strong></li></ul><ol><li><strong>每天 5 次机会</strong>：每生成一次消耗 1 次，每天 0 点重置，没用完的不累计。</li><li><strong>需要新录音</strong>：每次使用前，必须先至少有一条<strong>新的</strong>录音笔记。</li><li><strong>后台生成</strong>：点击发芽后大约需要 3-5 分钟，<strong>你不用盯着屏幕等</strong>，生成好了会给你发推送通知。</li></ol><h1 id="如何查看getseed录音卡的电量" tabindex="-1">如何查看GetSeed录音卡的电量 <a class="header-anchor" href="#如何查看getseed录音卡的电量" aria-label="Permalink to &quot;如何查看GetSeed录音卡的电量&quot;">​</a></h1><p>在Get笔记App首页，点击右上角，弹出设备列表，点击Get-XXX，进入设备信息页，可以看到电量和其它卡片信息。</p><h1 id="getseed休眠-引起的无法连接" tabindex="-1">GetSeed休眠 引起的无法连接 <a class="header-anchor" href="#getseed休眠-引起的无法连接" aria-label="Permalink to &quot;GetSeed休眠 引起的无法连接&quot;">​</a></h1><p>答：您长按GetSeed录音卡的Mark键1秒，看下能否正常连接，卡片本身会有休眠，也可以在Get笔记App里面找到卡片的信息页，对休眠时间进行设置。</p><h1 id="如何查看录音卡里的录音文件" tabindex="-1">如何查看录音卡里的录音文件？ <a class="header-anchor" href="#如何查看录音卡里的录音文件" aria-label="Permalink to &quot;如何查看录音卡里的录音文件？&quot;">​</a></h1><p>答：录音卡中录音文件，会在与Get笔记APP连接后，自动上传同步到手机上。</p><h1 id="录完后怎么没有看到录音上传呢" tabindex="-1">录完后怎么没有看到录音上传呢？ <a class="header-anchor" href="#录完后怎么没有看到录音上传呢" aria-label="Permalink to &quot;录完后怎么没有看到录音上传呢？&quot;">​</a></h1><p>答：可能是录音卡片还在录音中，录音中时无法进行录音文件上传，等结束录音后，可以自动上传。</p><h1 id="带手机壳能不能磁吸-手机壳有支架怎么磁吸" tabindex="-1">带手机壳能不能磁吸，手机壳有支架怎么磁吸 <a class="header-anchor" href="#带手机壳能不能磁吸-手机壳有支架怎么磁吸" aria-label="Permalink to &quot;带手机壳能不能磁吸，手机壳有支架怎么磁吸&quot;">​</a></h1><p>答：手机壳也可以磁吸卡套，不影响，如果手机壳背面有支架，会影响磁吸位置，建议更换下手机壳，或可以把录音卡单独携带使用</p><h1 id="会员到期后还能继续用吗-必须要买会员才能用吗" tabindex="-1">会员到期后还能继续用吗？必须要买会员才能用吗？ <a class="header-anchor" href="#会员到期后还能继续用吗-必须要买会员才能用吗" aria-label="Permalink to &quot;会员到期后还能继续用吗？必须要买会员才能用吗？&quot;">​</a></h1><p>答：</p><p>录音卡使用不受影响，可以继续录音，是否成为会员主要区别在于录音上传后，转写时长的不同。</p><p>免费用户，每个月会有 600分钟的免费转写时长。PRO会员，每个月转写时长不限制。</p><p>如果转写时长不够，可以再考虑买会员。</p><h1 id="配的红绿的绳子是干什么的" tabindex="-1">配的红绿的绳子是干什么的？ <a class="header-anchor" href="#配的红绿的绳子是干什么的" aria-label="Permalink to &quot;配的红绿的绳子是干什么的？&quot;">​</a></h1><p>答：可以绑在收纳盒外面，用于加固收纳盒。</p><h1 id="苹果手机用户-如果先从系统设置连接了getseed卡片-就无法从get笔记app内连接卡片" tabindex="-1">苹果手机用户，如果先从系统设置连接了GetSeed卡片，就无法从Get笔记App内连接卡片 <a class="header-anchor" href="#苹果手机用户-如果先从系统设置连接了getseed卡片-就无法从get笔记app内连接卡片" aria-label="Permalink to &quot;苹果手机用户，如果先从系统设置连接了GetSeed卡片，就无法从Get笔记App内连接卡片&quot;">​</a></h1><p>答：需要从手机系统设置-蓝牙-忽略Get-xxxx的设备，然后从Get笔记App内的侧边栏-&gt;录音卡片进行连接</p><h1 id="如果内存满了的话-是自动覆盖最开始的吗-还是有啥办法直接看录音卡的内容" tabindex="-1">如果内存满了的话，是自动覆盖最开始的吗？还是有啥办法直接看录音卡的内容？ <a class="header-anchor" href="#如果内存满了的话-是自动覆盖最开始的吗-还是有啥办法直接看录音卡的内容" aria-label="Permalink to &quot;如果内存满了的话，是自动覆盖最开始的吗？还是有啥办法直接看录音卡的内容？&quot;">​</a></h1><p>录音卡中的音频文件只要同步到手机里，就会清掉卡片中的文件，一般不会有内存压力。极限条件下，内存满了就会提示无法录音了。</p><h1 id="罗老师跨年中说的-主动-怎么体验到" tabindex="-1">罗老师跨年中说的“主动”怎么体验到？ <a class="header-anchor" href="#罗老师跨年中说的-主动-怎么体验到" aria-label="Permalink to &quot;罗老师跨年中说的“主动”怎么体验到？&quot;">​</a></h1><p>“发芽”——让AI<strong>主动</strong>了解你，再<strong>主动</strong>告诉你可以了解哪些问题、怎么更好地问AI。</p><p>您可以试试先生成一份发芽报告。</p><h1 id="隐私怎么保障" tabindex="-1">隐私怎么保障？ <a class="header-anchor" href="#隐私怎么保障" aria-label="Permalink to &quot;隐私怎么保障？&quot;">​</a></h1><p>笔记不设置公开分享的话，默认只有自己可见。数据严格加密隔离存储。数据绑定账号，非本人不可取，并且有硬件级防护，严禁外设导出。我们始终把用户隐私安全放在第一位，这个请放心。</p><h1 id="手机录音为什么还需要getseed" tabindex="-1">手机录音为什么还需要GetSeed？ <a class="header-anchor" href="#手机录音为什么还需要getseed" aria-label="Permalink to &quot;手机录音为什么还需要GetSeed？&quot;">​</a></h1><ul><li>盲操一秒开录：物理按键，不用看屏幕，拨动即录</li><li>录音不怕打断：独立运行，手机来电、消息都不影响</li><li>录得更清楚：3 麦克风 + 8 米收音 + AI 降噪</li><li>没有手机电量焦虑：35 小时连续录音，待机时长 60 天</li><li>通话全都能录：电话、微信视频、腾讯 / 钉钉 / 飞书会议</li><li>没网、没手机，也能录：64GB 本地存储，录完再同步</li></ul><h1 id="如何给录音卡充电-插手机上吗" tabindex="-1">如何给录音卡充电？插手机上吗？ <a class="header-anchor" href="#如何给录音卡充电-插手机上吗" aria-label="Permalink to &quot;如何给录音卡充电？插手机上吗？&quot;">​</a></h1><p>可以通过配备充电线，直接磁吸充电，type-c 的一端直接插在充电宝、或者type-c的充电头上就行。</p><p><img src="'+u+'" alt=""></p><h1 id="充电线丢了怎么办" tabindex="-1">充电线丢了怎么办？ <a class="header-anchor" href="#充电线丢了怎么办" aria-label="Permalink to &quot;充电线丢了怎么办？&quot;">​</a></h1><p>可点此购买链接下单：<a href="https://j.youzan.com/by9-yH" target="_blank" rel="noreferrer">https://j.youzan.com/by9-yH</a></p><h1 id="怎么知道录音卡连没连上-如何查看录音卡电量" tabindex="-1">怎么知道录音卡连没连上？如何查看录音卡电量？ <a class="header-anchor" href="#怎么知道录音卡连没连上-如何查看录音卡电量" aria-label="Permalink to &quot;怎么知道录音卡连没连上？如何查看录音卡电量？&quot;">​</a></h1><p>进入Get笔记APP，绑定过录音卡的，首页右上角会展示设备入口，设备展示灰色，表示未连接，设备展示绿色，表示已连接。</p><p>点击设备名称，进入设备信息页，也可以查看连接状态和电量。</p><p><img src="'+q+'" alt=""></p><p>未连接</p><p><img src="'+x+'" alt=""></p><p>已连接</p><p><img src="'+P+'" alt=""></p><p>电量显示</p><h1 id="录音卡丢了怎么办" tabindex="-1">录音卡丢了怎么办？ <a class="header-anchor" href="#录音卡丢了怎么办" aria-label="Permalink to &quot;录音卡丢了怎么办？&quot;">​</a></h1><p>卡片不与自己绑定的设备解绑，捡到卡片的人无法操作连接，数据安全有保障。</p><p>实在不放心，也可以联系get-notes@luojilab.com，发送基本的设备信息，如设备SN码、手机号等，登记挂失。</p><h1 id="录音卡充电满后灯一直是紫色-连手机上显示电量已-100-但灯未变绿-怎么回事" tabindex="-1">录音卡充电满后灯一直是紫色，连手机上显示电量已 100%，但灯未变绿，怎么回事？ <a class="header-anchor" href="#录音卡充电满后灯一直是紫色-连手机上显示电量已-100-但灯未变绿-怎么回事" aria-label="Permalink to &quot;录音卡充电满后灯一直是紫色，连手机上显示电量已 100%，但灯未变绿，怎么回事？&quot;">​</a></h1><p>手机上显示电量 100%，就说明已经<strong>充满电</strong>了，可以放心使用。</p><p>之所以灯还是紫色、没变绿，是因为：电量 100% 已经达到满电，但指示灯变绿需要再稍微多充一小段 “涓流补电”，这时候其实已经<strong>不会再往里充电</strong>，只是在做微小补电，对使用没有影响。</p><p>您可以这样操作试试：先关掉蓝牙，重新插拔一下充电线，等 3–4 分钟，一般就会变绿了。<strong>以手机上显示的 100% 电量为准就可以。</strong></p><h1 id="getseed-录音卡现在支持哪些语言识别-方言支持哪些" tabindex="-1">GetSeed 录音卡现在支持哪些语言识别？方言支持哪些？ <a class="header-anchor" href="#getseed-录音卡现在支持哪些语言识别-方言支持哪些" aria-label="Permalink to &quot;GetSeed 录音卡现在支持哪些语言识别？方言支持哪些？&quot;">​</a></h1><p>GetSeed现在支持 **中、英、日 **混合识别。</p><p>其中，中文包括：<strong>普通话</strong>、<strong>粤语</strong>、吴语、闽南语、客家话、赣语、湘语、晋语；并支持中原、西南、冀鲁、江淮、兰银、胶辽、东北、北京、港台等，包括河南、陕西、湖北、四川、重庆、云南、贵州、广东、广西、河北、天津、山东、安徽、南京、江苏、杭州、甘肃、宁夏等地区官话口音</p><h1 id="¥888-马上发芽-礼盒和之前的¥699普通款有什么区别" tabindex="-1">¥888“马上发芽”礼盒和之前的¥699普通款有什么区别？ <a class="header-anchor" href="#¥888-马上发芽-礼盒和之前的¥699普通款有什么区别" aria-label="Permalink to &quot;¥888“马上发芽”礼盒和之前的¥699普通款有什么区别？&quot;">​</a></h1><p>¥699是早鸟价，仅限刚发布阶段，标准款早鸟价售完就不会再有了。</p><p>新春版包装升级为银色科技质感 “发芽桶” 礼盒，内含可种植的小麦种子，可以用桶身直接种植当桌面绿植，还有春节限定的“马上发/马上发芽”封套，都是很好的寓意，非常适合新年送给自己或重要的人。</p><h1 id="oppo手机-为什么一连接上录音卡-微信的输入法就跳不出来了" tabindex="-1">OPPO手机，为什么一连接上录音卡，微信的输入法就跳不出来了？ <a class="header-anchor" href="#oppo手机-为什么一连接上录音卡-微信的输入法就跳不出来了" aria-label="Permalink to &quot;OPPO手机，为什么一连接上录音卡，微信的输入法就跳不出来了？&quot;">​</a></h1><p>安卓：设置 &gt; 蓝牙 &gt; 已配对录音卡旁的设置图标 &gt; 关闭 “输入设备”“键盘” 类选项。</p>',114)])])}const I=a(G,[["render",A]]);export{T as __pageData,I as default};
